import { DynamoDBClient, GetItemCommand } from "@aws-sdk/client-dynamodb";
import { getTenantContext, createResponse } from "tenant-utils";

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

/**
 * Fetch recaptcha_secret from amfaConfigs in DDB for the given tenant.
 * Falls back to RECAPTCHA_SECRET env var for backward compatibility.
 */
const getRecaptchaSecret = async (tenantContext) => {
  try {
    const params = {
      TableName: tenantContext.tableNames.configTable,
      Key: {
        id: { S: tenantContext.tenantId },
        configtype: { S: "amfaConfigs" },
      },
    };
    const result = await dynamodb.send(new GetItemCommand(params));
    if (result.Item?.value?.S) {
      const config = JSON.parse(result.Item.value.S);
      if (config.recaptcha_secret) {
        return config.recaptcha_secret;
      }
    }
  } catch (err) {
    console.warn(
      `Failed to fetch recaptcha_secret from DDB for tenant ${tenantContext.tenantId}:`,
      err.message,
    );
  }
  // Fallback to env var for backward compatibility
  return process.env.RECAPTCHA_SECRET || "";
};

export const handler = async (event, context, callback) => {
  console.log("event:", event);

  const payload = JSON.parse(event.body);
  try {
    // Extract tenant context from request
    const tenantContext = await getTenantContext(event);
    console.log("Tenant context for recaptcha:", tenantContext.tenantId);

    // Get recaptcha secret from DDB (per-tenant) or fallback to env var
    const recaptchaSecret = await getRecaptchaSecret(tenantContext);

    if (!recaptchaSecret) {
      console.error(
        "No recaptcha secret configured for tenant:",
        tenantContext.tenantId,
      );
      return createResponse(
        500,
        { success: false, error: "reCAPTCHA not configured" },
        tenantContext.tenantId,
      );
    }

    const recaptRes = await fetch(
      "https://www.google.com/recaptcha/api/siteverify",
      {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: `secret=${recaptchaSecret}&response=${payload.token}`,
      },
    );

    console.log("recaptRes:", recaptRes);

    const recaptResBody = await recaptRes.json();
    console.log("recaptResBody:", recaptResBody);

    return createResponse(
      200,
      {
        success: recaptResBody.success === true,
      },
      tenantContext.tenantId,
    );
  } catch (e) {
    console.error("verifyrecaptcha error:", e);

    // Try to get tenant ID for error response
    let tenantId = null;
    try {
      const tenantContext = await getTenantContext(event);
      tenantId = tenantContext.tenantId;
    } catch (tenantError) {
      // ignore
    }

    return createResponse(500, { success: false }, tenantId);
  }
};
